just as a follow up, I read up on the [http](https://pub.dev/packages/http) package and it shows the browser client doesn't have caching, so I switched to using fetch_client and made an explicit memory image:
```
static final FetchClient _client = FetchClient(mode: RequestMode.cors);

  static Future<Uint8List> getBytes(String url) async {
    FetchResponse response = await _client.send(http.Request("GET", Uri.parse(url)));
    if(response.statusCode == 200) {
      return response.stream.toBytes();
    }
    return Uint8List(0);
  }

  bool _isLoading = true;
  Image? _userImage;
  Future<void> _init() async {

    Uint8List imageBytes = await getBytes(FirebaseAuth.instance.currentUser!.photoURL!);
    Image memoryImage;
    if(imageBytes.isNotEmpty) {
      memoryImage = Image.memory(imageBytes);
    }
    else {
      memoryImage = await createBlankImageWidget(96, 96);
    }
    setState(() {
      _isLoading = false;
      _userImage = memoryImage;
    });
  }

Widget _buildUserIcon(BuildContext context) {
    if(_isLoading) {
      return Padding(
        padding: const EdgeInsets.all(8.0),
        child: CircularProgressIndicator(),
      );
    }
    if(_userImage == null) {
      return Padding(
        padding: const EdgeInsets.all(8.0),
        child: Icon(Icons.account_circle_outlined),
      );
    }
    return Padding(
      padding: const EdgeInsets.all(8.0),
      child: CircleAvatar(
        backgroundImage: _userImage!.image,
      ),
    );

  }

```

this works now after removing the `--web-renderer=html` flag
